import React, { useEffect, useRef, useState } from 'react';
import styles from './ChatWindow.module.css';

function statusIcon(status) {
  if (status === 'Sent')      return <span className={styles.statusSent}>✓</span>;
  if (status === 'Delivered') return <span className={styles.statusDelivered}>✓✓</span>;
  if (status === 'Read')      return <span className={styles.statusRead}>✓✓</span>;
  return null;
}

function MessageBubble({ msg, isMine }) {
  const time = new Date(msg.sentAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  return (
    <div className={`${styles.msgRow} ${isMine ? styles.mine : styles.theirs}`}>
      <div className={styles.bubble}>{msg.content}</div>
      <div className={styles.meta}>
        <span className={styles.time}>{time}</span>
        {isMine && statusIcon(msg.status)}
      </div>
    </div>
  );
}

export default function ChatWindow({ peer, messages, myId, isTyping, onSend, onTyping }) {
  const [text, setText]   = useState('');
  const bottomRef         = useRef(null);
  const typingSentRef     = useRef(false);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isTyping]);

  const handleSend = () => {
    if (!text.trim()) return;
    onSend(text.trim());
    setText('');
  };

  const handleKey = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend(); }
  };

  const handleInput = (e) => {
    setText(e.target.value);
    if (!typingSentRef.current) {
      typingSentRef.current = true;
      onTyping();
      setTimeout(() => { typingSentRef.current = false; }, 2000);
    }
  };

  if (!peer) {
    return (
      <div className={styles.empty}>
        <div className={styles.emptyIcon}>💬</div>
        <h2 className={styles.emptyTitle}>Start a conversation</h2>
        <p className={styles.emptySub}>Select someone from the list to begin chatting.</p>
      </div>
    );
  }

  const initials = peer.name[0].toUpperCase();

  return (
    <div className={styles.panel}>
      <div className={styles.bgPattern} />

      <div className={styles.header}>
        <div className={`${styles.avatar} ${styles.lg}`}>{initials}</div>
        <div className={styles.headerInfo}>
          <div className={styles.peerName}>{peer.name}</div>
          <div className={`${styles.peerStatus} ${isTyping ? styles.typing : ''}`}>
            {isTyping ? 'Typing…' : 'Online'}
          </div>
        </div>
      </div>

      <div className={styles.messages}>
        <div className={styles.dateDivider}>Today</div>
        {messages.map((m) => (
          <MessageBubble key={m.id} msg={m} isMine={m.senderId === myId} />
        ))}
        {isTyping && (
          <div className={`${styles.msgRow} ${styles.theirs}`}>
            <div className={`${styles.bubble} ${styles.typingBubble}`}>
              <span className={styles.dot1} /><span className={styles.dot2} /><span className={styles.dot3} />
            </div>
          </div>
        )}
        <div ref={bottomRef} />
      </div>

      <div className={styles.inputArea}>
        <div className={styles.inputWrapper}>
          <input
            className={styles.input}
            type="text"
            placeholder="Send a message…"
            value={text}
            onChange={handleInput}
            onKeyDown={handleKey}
          />
          <button className={styles.sendBtn} onClick={handleSend}>➤</button>
        </div>
      </div>
    </div>
  );
}
